import{_ as r,o as t,c as p,j as a,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const n="/assets/%E5%A4%A9%E5%90%AF.DUQU22Bc.png",m=JSON.parse('{"title":"千禧骑士下属专长","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/专长/千禧骑士下属专长.md","filePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/专长/千禧骑士下属专长.md"}'),_={name:"4.资源分区/1.血统与训练/4.综合类/千禧骑士/专长/千禧骑士下属专长.md"};function d(l,e,i,c,b,h){return t(),p("div",null,[...e[0]||(e[0]=[a("h1",{id:"千禧骑士下属专长",tabindex:"-1"},[s("千禧骑士下属专长 "),a("a",{class:"header-anchor",href:"#千禧骑士下属专长","aria-label":'Permalink to "千禧骑士下属专长"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),o('<h1 id="千禧骑士下属专长-1" tabindex="-1">千禧骑士下属专长 <a class="header-anchor" href="#千禧骑士下属专长-1" aria-label="Permalink to &quot;千禧骑士下属专长&quot;">​</a></h1><p>千禧骑士下属专长</p><p><img src="'+n+'" alt=""></p><p>晨昏对峙（1）<br> 1级：当一个场景中有且仅有包括千禧骑士在内的三人时，千禧骑士的社交检定获得1点检定加值，并获得对场景内其余两人而言的D级免措手不及和D级先制。<br> “For a Few Dollars More”</p><p>信手空空（1）<br> 1级：现在，千禧骑士在携带任何千禧骑士下属武器时，这些武器的体积统一算作人物可携带范围，无论携带多少件都不会计入携带上限内。现在，千禧骑士也可以将下属武器装入戒指、手环等经常被用于魔法储物的位置中，取出这些武器使用迅捷动作。<br> “人人为我”</p><p>傀儡师（3）<br> 3级：现在，千禧骑士在每次对被攻击目标进行攻击且成功造成伤害时，该目标还需再进行一次意志豁免以对抗这次伤害出目，若至少造成了1点成功数，则其二者差值/3每有1点（不足1时视为1），其身上会出现一道傀儡丝线，并积累1点成功数。当积累的成功数超过其沉着/决心的较高值时，你能够指定目标在下一轮内的标准动作与移动动作如何使用，你所指定的使用方案不能够对目标自身造成直接的伤害或是负面效果，这是一个B级心灵来源的支配效果。每个单位一场景只能被这一效果影响一次。<br> “做君主的人，不要对招来吝啬之名有所介意”</p><p>布罗迪报告（3）<br> 3级：现在，每场影片中，千禧骑士每曾支配过或对某一同等级敌人造成二档异常点数毁灭，就获得1点全检定上的表现加值，每场影片结束时清零。<br> “仇恨的根源总是暧昧不清的。”</p><p>拍卖第49批/全景监狱/世界夫人只能选择一项购买</p><p>拍卖第49批（3）<br> 3级：当你进行隐秘检定时，可以最多在那次检定上扣除等同于传奇沉着*2点隐秘检定上的加值，并获得等量的附加成功，最多不超过5点。被攻击者也可以选择自行流失其拥有的通用能量或意志，以每流失9通用能量或1意志抵销1附加成功的方式抵销这些附加成功。</p><p>全景监狱（3）<br> 3级：当你进行洞察检定时，可以最多在那次检定上扣除等同于等同于传奇操控*2点沉着检定上的加值，并获得等量的附加成功，最多不超过5点。被攻击者也可以选择暂时遗忘其拥有的能力，以每遗忘1项D级强化抵销2附加成功的方式抵销这些附加成功，遗忘能力将持续一轮。</p><p>世界夫人（3）<br> 3级：当你进行社交检定时，可以最多在那次检定上扣除等同于等同于传奇风度*2点社交检定上的加值，并获得等量的附加成功，最多不超过5点。被攻击者也可以选择自行承受风度易伤，以每承受1点风度易伤的方式抵销1附加成功的方式抵销这些附加成功，承受的易伤将持续存在一轮。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const g=r(_,[["render",d]]);export{m as __pageData,g as default};
